-- ============================================================================
-- Quiz Seed: Job Chapters 22–31
-- 3 difficulties × 10 chapters = 160 total questions
-- Kids: 3 per chapter | Teens: 5 per chapter | Adults: 8 per chapter
-- ============================================================================

-- ═══ Job Chapter 22 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Job', 22, 'kids', 1, 'Who is speaking in Job chapter 22?', 'Eliphaz the Temanite', 'Bildad the Shuhite', 'Zophar the Naamathite', 'Elihu the Buzite', 'a', 'Job 22:1 — "Then Eliphaz the Temanite answered and said." This is Eliphaz''s third and final speech to Job.'),
('Job', 22, 'kids', 2, 'What did Eliphaz tell Job to do so that good would come to him?', 'Acquaint now thyself with him, and be at peace', 'Pray without ceasing until God answers', 'Offer sacrifices at the altar', 'Ask his friends to pray on his behalf', 'a', 'Job 22:21 — "Acquaint now thyself with him, and be at peace: thereby good shall come unto thee."'),
('Job', 22, 'kids', 3, 'What did Eliphaz say would happen when Job prayed if he returned to God?', 'Thou shalt make thy prayer unto him, and he shall hear thee', 'God would restore his flocks immediately', 'His friends would rejoice with him', 'The clouds would bring rain to his fields', 'a', 'Job 22:27 — "Thou shalt make thy prayer unto him, and he shall hear thee, and thou shalt pay thy vows."'),
-- Teens
('Job', 22, 'teens', 1, 'What question did Eliphaz ask at the opening of his speech about whether Job could benefit God?', 'Can a man be profitable unto God, as he that is wise may be profitable unto himself?', 'Is it any pleasure to the Almighty that thou art righteous?', 'Doth God pervert judgment or doth the Almighty pervert justice?', 'Shall any teach God knowledge, seeing he judgeth those that are high?', 'a', 'Job 22:2 — "Can a man be profitable unto God, as he that is wise may be profitable unto himself?"'),
('Job', 22, 'teens', 2, 'What specific social sins did Eliphaz falsely accuse Job of committing?', 'Taking pledges from brothers and stripping the naked of their clothing, withholding water and bread from the weary', 'Cheating his workers of their wages and stealing from widows', 'Worshipping idols and turning away from the Sabbath', 'Oppressing the judges and bribing the princes', 'a', 'Job 22:6-7 — "For thou hast taken a pledge from thy brother for nought, and stripped the naked of their clothing. Thou hast not given water to the weary to drink, and thou hast withholden bread from the hungry."'),
('Job', 22, 'teens', 3, 'What did Eliphaz say Job thought about the clouds and God''s ability to see?', 'Job thought God could not see through the thick clouds that are a covering to him', 'Job believed God watched from heaven with perfect knowledge of every deed', 'Job claimed the clouds were signs of God''s blessing on the wicked', 'Job argued that God hid himself in the clouds to escape man''s prayers', 'a', 'Job 22:13-14 — "Thou sayest, How doth God know? can he judge through the dark cloud? Thick clouds are a covering to him, that he seeth not."'),
('Job', 22, 'teens', 4, 'What happened to the old way in which the wicked were cut down, according to Eliphaz?', 'Which were cut down out of time, whose foundation was overflown with a flood', 'They were swallowed up by the earth as in the days of Korah', 'Their houses were burned and their cattle scattered', 'They were driven into the wilderness never to return', 'a', 'Job 22:16 — "Which were cut down out of time, whose foundation was overflown with a flood."'),
('Job', 22, 'teens', 5, 'What promise did Eliphaz make about what would happen to Job if he returned to the Almighty?', 'The Almighty shall be thy defence and thou shalt have plenty of silver', 'Thou shalt be restored unto thy former glory and riches', 'God shall send angels to guard thee from all calamity', 'Thy children shall be restored and thy wife shall rejoice', 'a', 'Job 22:25 — "Yea, the Almighty shall be thy defence, and thou shalt have plenty of silver."'),
-- Adults
('Job', 22, 'adults', 1, 'What theological argument did Eliphaz make in Job 22:2-3 to claim that Job''s suffering could not be due to his righteousness?', 'He argued that God gains nothing from human righteousness and therefore Job''s righteous character could not profit God or cause Him to bless Job', 'He claimed that all suffering is proportional to sin and Job must have sinned greatly', 'He argued that God is too exalted to care about individual human righteousness', 'He asserted that Job''s pride in his own righteousness was itself a sin deserving punishment', 'a', 'Job 22:2-3 — "Can a man be profitable unto God...Is it any pleasure to the Almighty, that thou art righteous? or is it gain to him, that thou makest thy ways perfect?" Eliphaz''s logic detaches divine blessing from human righteousness, implying Job must have sinned.'),
('Job', 22, 'adults', 2, 'What fabricated sins did Eliphaz accuse Job of regarding widows and orphans?', 'Thou hast sent widows away empty and the arms of the fatherless have been broken', 'Thou didst take the ox of the widow and leave her children to starve', 'Thou didst refuse to judge the cause of the widow at the city gate', 'Thou didst marry a widow''s daughter and deny her mother''s inheritance', 'a', 'Job 22:9 — "Thou hast sent widows away empty, and the arms of the fatherless have been broken." These accusations are directly refuted by Job''s oath of innocence in Job 31.'),
('Job', 22, 'adults', 3, 'What does Eliphaz''s accusation in Job 22:13-14 reveal about the false view of God he attributed to Job?', 'He accused Job of believing that God could not see through the thick clouds and therefore could not judge human behaviour from heaven', 'He claimed Job denied God''s existence because of his suffering', 'He said Job believed God punished the righteous out of indifference', 'He accused Job of thinking that God only watched the affairs of angels, not men', 'a', 'Job 22:13-14 — "Thou sayest, How doth God know? can he judge through the dark cloud? Thick clouds are a covering to him, that he seeth not; and he walketh in the circuit of heaven." Eliphaz put deistic ignorance into Job''s mouth that Job never expressed.'),
('Job', 22, 'adults', 4, 'How did Eliphaz use the fate of the wicked in Job 22:15-18 as an argument against Job?', 'He warned Job not to keep to the old way of wicked men who were cut off before their time and whose foundation was overflown with a flood', 'He cited the destruction of Sodom as a warning that God judges the proud', 'He pointed to the flood of Noah as evidence that God destroys the unjust generation', 'He invoked the fate of Korah''s company as a model for what awaited Job', 'a', 'Job 22:15-16 — "Hast thou marked the old way which wicked men have trodden? Which were cut down out of time, whose foundation was overflown with a flood." Eliphaz implies Job is walking the same doomed path as the ancient wicked.'),
('Job', 22, 'adults', 5, 'What does Eliphaz''s counsel "receive, I pray thee, the law from his mouth" in Job 22:22 assume about Job''s spiritual condition?', 'It assumes Job has turned away from God''s word and needs to return to receiving divine instruction as if he were an estranged sinner', 'It is an invitation to study Torah alongside Eliphaz as a fellow learner', 'It acknowledges that Job''s suffering has made him open to new spiritual teaching', 'It suggests that Job had never truly known God''s law before his afflictions', 'a', 'Job 22:22 — "Receive, I pray thee, the law from his mouth, and lay up his words in thine heart." The counsel assumes Job has abandoned God''s instruction, which contradicts the divine verdict in Job 1:8 that Job was "perfect and upright."'),
('Job', 22, 'adults', 6, 'What is the irony of Eliphaz''s promise in Job 22:29-30 that the humble will be saved?', 'Eliphaz promises that God saves the humble and the innocent, yet he himself is humbling Job with false accusations, while Job is in fact the innocent one God will eventually vindicate', 'There is no irony; Eliphaz''s theology is vindicated at the end of the book', 'The irony is that Job refuses to be humble even after Eliphaz''s counsel', 'The irony lies in Eliphaz being a foreigner who presumes to teach an Israelite about God''s ways', 'a', 'Job 22:29-30 — "He shall deliver the island of the innocent: and it is delivered by the pureness of thine hands." Ironically, Job is the innocent one, and God ultimately rebukes Eliphaz (Job 42:7) — "ye have not spoken of me the thing that is right, as my servant Job hath."'),
('Job', 22, 'adults', 7, 'How does Eliphaz''s third speech in Job 22 differ from his first two speeches in its directness?', 'Unlike his earlier speeches that spoke of suffering in general terms, the third speech directly and specifically accuses Job of named sins such as stripping the naked, withholding bread, and sending widows away empty', 'The third speech is softer and more sympathetic, offering comfort rather than condemnation', 'The third speech focuses entirely on future hope without revisiting Job''s alleged sin', 'The third speech introduces new theological arguments about angelic witnesses to Job''s sin', 'a', 'Job 22:6-9 — Eliphaz now makes specific personal accusations: "thou hast taken a pledge from thy brother...stripped the naked...Thou hast not given water to the weary...sent widows away empty." Earlier speeches were more general in their retribution theology.'),
('Job', 22, 'adults', 8, 'What does Eliphaz''s vision of gold being worthless compared to God — "the Almighty shall be thy gold, and thy precious silver" — reveal about his understanding of Job''s root problem?', 'He believed Job''s primary sin was trusting in material wealth rather than in God, and his restoration would come only when he made the Almighty his treasure', 'He was acknowledging that Job had lost all his wealth and needed divine compensation', 'He was comparing God''s value to market prices of precious metals in ancient Uz', 'He was quoting a proverb about wealth that was well-known among the eastern sages', 'a', 'Job 22:24-25 — "Then shalt thou lay up gold as dust...Yea, the Almighty shall be thy defence, and thou shalt have plenty of silver." Eliphaz frames the problem as misplaced treasure, urging Job to value God above wealth — a valid principle applied to an innocent man.');

-- ═══ Job Chapter 23 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Job', 23, 'kids', 1, 'What did Job wish he could do at the beginning of chapter 23?', 'Find God and come even to his seat', 'Pray loudly so his friends would hear', 'Sleep until his suffering was over', 'Ask an angel to carry his complaint to heaven', 'a', 'Job 23:3 — "Oh that I knew where I might find him! that I might come even to his seat!"'),
('Job', 23, 'kids', 2, 'What did Job say God knew about him that gave him hope?', 'He knoweth the way that I take; when he hath tried me, I shall come forth as gold', 'God had written his name in the book of life', 'The Lord had counted every hair on his head', 'God remembered all the good deeds he had done', 'a', 'Job 23:10 — "But he knoweth the way that I take: when he hath tried me, I shall come forth as gold."'),
('Job', 23, 'kids', 3, 'What had Job kept and not turned away from?', 'The commandment of his lips and the words of his mouth', 'The path of the righteous that his father taught him', 'The law written on stone tablets by Moses', 'The counsel of his oldest and wisest friend', 'a', 'Job 23:12 — "Neither have I gone back from the commandment of his lips; I have esteemed the words of his mouth more than my necessary food."'),
-- Teens
('Job', 23, 'teens', 1, 'What did Job say he would do if he could find God and come before him?', 'I would order my cause before him and fill my mouth with arguments', 'I would fall on my face and beg for mercy and forgiveness', 'I would ask him to explain every trial he had sent upon me', 'I would present my friends as witnesses of my integrity', 'a', 'Job 23:4 — "I would order my cause before him, and fill my mouth with arguments."'),
('Job', 23, 'teens', 2, 'What did Job hope God would do when he presented his case to him?', 'He would regard me; so would I be delivered for ever from my judge', 'He would restore my children and my flocks at once', 'He would silence my friends with a voice from heaven', 'He would write a scroll declaring my innocence to all nations', 'a', 'Job 23:7 — "There the righteous might dispute with him; so should I be delivered for ever from my judge."'),
('Job', 23, 'teens', 3, 'What frustrated Job about his search for God in chapter 23?', 'He looked forward and backward, to the left and right, but could not find God', 'God had answered him only with silence for many months', 'His prayers returned to him unanswered like a sealed letter', 'The mountains blocked his view of heaven so he could not see God''s throne', 'a', 'Job 23:8-9 — "Behold, I go forward, but he is not there; and backward, but I cannot perceive him: On the left hand, where he doth work, but I cannot behold him: he hideth himself on the right hand, that I cannot see him."'),
('Job', 23, 'teens', 4, 'How did Job describe his devotion to God''s words compared to his physical needs?', 'I have esteemed the words of his mouth more than my necessary food', 'I have treasured God''s law above silver and rubies', 'I have honoured his commandments more than life itself', 'I have loved his precepts more than the songs of the righteous', 'a', 'Job 23:12 — "I have esteemed the words of his mouth more than my necessary food."'),
('Job', 23, 'teens', 5, 'What emotion gripped Job when he thought about God''s power at the end of chapter 23?', 'He was troubled because of the darkness, and soft darkness covered his face', 'He was filled with dread because of the terrors of the Almighty', 'He cried out in anguish and his heart failed within him', 'He trembled with fear and his knees became like water', 'a', 'Job 23:15-16 — "Therefore am I troubled at his presence: when I consider, I am afraid of him. For God maketh my heart soft, and the Almighty troubleth me: Because I was not cut off before the darkness, neither hath he covered the darkness from my face."'),
-- Adults
('Job', 23, 'adults', 1, 'What does Job''s opening lament in Job 23:2 — "my stroke is heavier than my groaning" — reveal about his psychological state?', 'It indicates that Job''s inner pain and sense of divine abandonment surpassed his ability to express it verbally; his groaning was inadequate for his actual suffering', 'It is a medical description of the physical weight of his sores pressing on his body', 'It shows Job was too proud to groan openly before his friends and God', 'It suggests Job had moved beyond grief into stoic acceptance of his condition', 'a', 'Job 23:2 — "Even to day is my complaint bitter: my stroke is heavier than my groaning." The verse captures Job''s existential anguish — his suffering exceeds articulation, reflecting the depth of his spiritual crisis.'),
('Job', 23, 'adults', 2, 'What does Job''s confidence in Job 23:4 — "I would order my cause before him, and fill my mouth with arguments" — reveal about his theology compared to his friends''?', 'Unlike his friends who insisted Job must confess sin, Job maintained that he had a legal case to present before God and trusted God to be a fair judge who would hear him', 'Job had abandoned hope in God''s mercy and was substituting a legal argument for repentance', 'Job was arrogantly claiming equality with God by demanding a formal hearing', 'Job was using courtroom language to mock his friends'' legal style of argument', 'a', 'Job 23:4 — "I would order my cause before him, and fill my mouth with arguments." Job''s judicial confidence contrasts with his friends'' demand for confession; he believes God''s own justice will vindicate him if he can only be heard.'),
('Job', 23, 'adults', 3, 'How does Job 23:10 — "when he hath tried me, I shall come forth as gold" — function as a confession of faith in the middle of his despair?', 'Job affirms that God''s purpose in his suffering is refining rather than punishing; the trial is purposeful and will result in proven purity, even though Job cannot perceive God''s presence', 'Job is predicting that his suffering will soon end and God will physically restore his wealth', 'Job is quoting a proverb about metallurgy to illustrate his hope for physical healing', 'Job is conceding that he has impurities that God is burning away through his suffering', 'a', 'Job 23:10 — "But he knoweth the way that I take: when he hath tried me, I shall come forth as gold." The gold-refining metaphor transforms the trial from punishment into purification, expressing trust in divine purpose even while God is hidden.'),
('Job', 23, 'adults', 4, 'What does Job''s fourfold search — forward, backward, left, right — in Job 23:8-9 communicate about the experience of divine hiddenness?', 'It communicates a comprehensive, exhausting search in every direction that yields no divine presence, expressing the reality that God''s hiddenness is total and disorienting to the sufferer', 'It is a poetic description of Job''s physical wandering across the land of Uz', 'It indicates Job has searched all the sacred sites of the ancient Near East for a shrine to God', 'It expresses Job''s growing doubt that God exists at all', 'a', 'Job 23:8-9 — "I go forward, but he is not there; and backward, but I cannot perceive him: On the left hand...I cannot behold him: he hideth himself on the right hand." The four directions represent totality — there is no orientation point from which Job can locate God.'),
('Job', 23, 'adults', 5, 'What is the significance of Job''s claim in Job 23:12 that he esteemed God''s words "more than my necessary food"?', 'It echoes Deuteronomy 8:3 — that man does not live by bread alone — and shows Job''s commitment to God''s word surpasses even biological survival, making his integrity unassailable', 'It is a boast about his fasting practices during his time of suffering', 'It is a comparison intended to shame his friends for thinking about food while he suffered', 'It shows that Job read the Torah more diligently than the priests of Israel', 'a', 'Job 23:12 — "I have esteemed the words of his mouth more than my necessary food." The comparison to necessary food (Hebrew: chukki — my statute/portion) echoes Deut 8:3, deepening the declaration of total devotion to divine instruction.'),
('Job', 23, 'adults', 6, 'What theological tension is at the heart of Job 23:13-14 — "he is in one mind, and who can turn him? and what his soul desireth, even that he doeth"?', 'Job acknowledges God''s sovereign immutability — that God''s purposes cannot be turned — and this very sovereignty is what both terrifies him and grounds his hope that God''s design for him will be completed', 'Job is expressing fatalism, believing that God is arbitrary and cannot be reasoned with', 'Job is accusing God of being capricious and indifferent to human suffering', 'Job is comparing God''s stubbornness to his friends'' refusal to listen to his arguments', 'a', 'Job 23:13-14 — "he is in one mind, and who can turn him?...he performeth the thing that is appointed for me." God''s immutability is a double-edged comfort: it means his refining purpose will be completed, but also that Job cannot escape the appointed trial.'),
('Job', 23, 'adults', 7, 'How does Job 23:15-16 resolve the tension between Job''s confident faith and his fear of God?', 'Both faith and fear coexist — Job is simultaneously confident in his innocence (v.10-12) and terrified by God''s overwhelming power (v.15-16), showing mature faith that does not require emotional resolution to maintain integrity', 'Job''s fear overtakes his faith by the end of the chapter, leaving him in despair', 'Job''s confidence overcomes his fear, and he ends the chapter with calm assurance', 'The tension is unresolved because Job refuses to pray, showing a breakdown in his relationship with God', 'a', 'Job 23:15-16 — "Therefore am I troubled at his presence: when I consider, I am afraid of him. For God maketh my heart soft." Yet this fear follows his declaration of integrity in v.10-12. Both truths are held simultaneously — a hallmark of authentic faith.'),
('Job', 23, 'adults', 8, 'How does Job chapter 23 contribute to the overall theological argument of the book against the friends'' retribution theology?', 'Job demonstrates that a righteous person can maintain moral integrity, value God''s word above all, and still be completely hidden from God''s presence — directly disproving the friends'' claim that suffering is always evidence of sin', 'Job chapter 23 supports the friends'' position by showing that Job''s doubt proves he has sinned', 'Job chapter 23 shows that suffering ultimately drives even the righteous to abandon God', 'The chapter is primarily a lament with no theological argument against the friends', 'a', 'Job 23:10-12 — "he knoweth the way that I take...I have kept his way...esteemed the words of his mouth more than my necessary food." Job''s sustained integrity amid hiddenness refutes the mechanical sin-suffering equation that the three friends champion throughout the dialogue.');

-- ═══ Job Chapter 24 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Job', 24, 'kids', 1, 'What did Job say the wicked do to helpless people in the fields?', 'They remove landmarks and violently take away flocks and feed', 'They tear down the houses of the poor at night', 'They burn the crops of the needy at harvest time', 'They drive the orphans away from the wells', 'a', 'Job 24:2 — "Some remove the landmarks; they violently take away flocks, and feed thereof."'),
('Job', 24, 'kids', 2, 'What did Job say poor people had to do for lack of shelter?', 'They cause him to go naked without clothing and they take away the sheaf from the hungry', 'They slept in caves and ate the grass of the fields', 'They wandered in the desert without food or water', 'They hid in the mountains to escape the wicked', 'a', 'Job 24:10 — "They cause him to go naked without clothing, and they take away the sheaf from the hungry."'),
('Job', 24, 'kids', 3, 'According to Job, does God immediately punish the wicked?', 'No, God does not charge them with folly even though they do great evil', 'Yes, God strikes them down before the next new moon', 'Yes, God sends a flood to wash away their wickedness', 'No, but angels record their deeds in a great book', 'a', 'Job 24:12 — "Men groan from out of the city, and the soul of the wounded crieth out: yet God layeth not folly to them."'),
-- Teens
('Job', 24, 'teens', 1, 'What question did Job open chapter 24 with regarding God''s timing?', 'Why, seeing times are not hidden from the Almighty, do they that know him not see his days?', 'How long will the wicked prosper while the righteous suffer in silence?', 'Doth God not count the months of the innocent and set a time for their deliverance?', 'Why hath God hidden his face from the city where the oppressed cry out?', 'a', 'Job 24:1 — "Why, seeing times are not hidden from the Almighty, do they that know him not see his days?"'),
('Job', 24, 'teens', 2, 'What did Job say the wicked do to the widow''s ox and the fatherless?', 'They drive away the ass of the fatherless and take the widow''s ox for a pledge', 'They steal the widow''s inheritance and sell her ox in the marketplace', 'They slaughter the ox before the widow and give nothing to the fatherless', 'They seize the ox at harvest and leave the widow to glean in their fields', 'a', 'Job 24:3 — "They drive away the ass of the fatherless, they take the widow''s ox for a pledge."'),
('Job', 24, 'teens', 3, 'How did Job describe the poor gleaning in the fields like the wicked''s harvest hands?', 'They glean in the vineyard of the wicked and gather the vintage of the wicked', 'They follow behind the reapers and catch what falls to the ground', 'They beg at the gate and receive the leavings from the threshing floor', 'They work the fields from dawn to dusk and receive nothing but a crust', 'a', 'Job 24:6 — "They reap every one his corn in the field: and they gather the vintage of the wicked."'),
('Job', 24, 'teens', 4, 'What did Job say about the murderer and adulterer regarding the darkness and light?', 'The murderer rising with the light killeth the poor, and in the night the adulterer is as the thief', 'They hide themselves in the caves by day and come out to do evil at midnight', 'The wicked love darkness more than light because their deeds are evil', 'They commit their sins at high noon when no one expects wickedness', 'a', 'Job 24:14-15 — "The murderer rising with the light killeth the poor and needy, and in the night is as a thief. The eye also of the adulterer waiteth for the twilight."'),
('Job', 24, 'teens', 5, 'What did Job say would be the end of the wicked man, even if he seemed exalted for a time?', 'He is exalted for a little while, but then he is gone; he shall be brought low and gathered as all others', 'He shall eat of the fruit of his evil deeds until they choke him', 'His house shall be burned and his children scattered to the winds', 'He shall rise no more and his name shall be forgotten even by his own family', 'a', 'Job 24:24 — "They are exalted for a little while, but are gone and brought low; they are taken out of the way as all other, and cut off as the tops of the ears of corn."'),
-- Adults
('Job', 24, 'adults', 1, 'What is the theological problem that Job raises in Job 24:1 about "times" and the Almighty, and why is it significant in the book''s argument?', 'Job challenges the idea that God''s judgment times are predictable, arguing that God does not visibly vindicate the righteous on a schedule that believers can observe, undermining the friends'' neat retribution theology', 'Job is claiming that God has hidden the prophetic timetable from human beings', 'Job is arguing that the Almighty does not know when the wicked commit their crimes', 'Job is complaining that God only reveals his times to privileged prophets like Abraham', 'a', 'Job 24:1 — "Why, seeing times are not hidden from the Almighty, do they that know him not see his days?" Job''s point is that if God knows all appointed times, why does his judicial intervention appear invisible to those who fear him?'),
('Job', 24, 'adults', 2, 'How does Job''s catalogue of wicked deeds in Job 24:2-12 function as an implicit defence of his own innocence?', 'By detailing the sins of oppressors — removing landmarks, taking pledges, exploiting the poor — Job implicitly contrasts himself with them, showing he has done none of these things and therefore cannot deserve punishment on retribution grounds', 'Job is warning his friends that they themselves commit these social sins', 'Job is providing a legal brief against specific enemies in the land of Uz', 'Job is quoting from a wisdom tradition to show that wickedness is universal', 'a', 'Job 24:2-9 details removing landmarks, stealing flocks, exploiting the hungry, taking the widow''s ox. In Job 31 Job swears oaths of innocence on these exact categories — the catalogue here sets up his later self-defence.'),
('Job', 24, 'adults', 3, 'What does Job 24:12 — "yet God layeth not folly to them" — express about Job''s complaint against divine justice?', 'It expresses Job''s anguish that God does not charge the wicked with wrongdoing even as the oppressed groan and cry out from the cities, making divine silence complicit in suffering', 'It is an accusation that God is foolish for not punishing the wicked immediately', 'It suggests Job believed God had forgotten the wicked''s sins but would eventually remember them', 'It shows Job agreeing with his friends that the wicked are punished slowly rather than immediately', 'a', 'Job 24:12 — "Men groan from out of the city, and the soul of the wounded crieth out: yet God layeth not folly to them." The verse places God''s inaction alongside human cries of anguish, posing the sharpest possible challenge to easy retribution theology.'),
('Job', 24, 'adults', 4, 'How does the light/darkness imagery for the murderer and adulterer in Job 24:13-17 develop Job''s argument about the wicked prospering?', 'The wicked have inverted the moral order — they rebel against the light and use darkness as cover, yet this inversion itself goes unchecked by God, reinforcing Job''s point about the absence of visible divine justice', 'Job uses light and darkness to distinguish sins of the day from sins of the night in Mosaic law', 'The imagery is purely poetic with no argumentative function in Job''s case against his friends', 'Job argues that the wicked are punished by their own fear of the light, which is itself divine retribution', 'a', 'Job 24:13 — "They are of those that rebel against the light...they know not the ways thereof." The wicked''s deliberate flight from light represents rebellion against God''s moral order, yet God does not immediately strike them down.'),
('Job', 24, 'adults', 5, 'What does Job''s description of the poor lodging naked in the cold and wet in Job 24:7-8 contribute to the book''s ethics?', 'It demonstrates that Job is acutely sensitive to the suffering of the vulnerable, which is consistent with his self-defence in chapter 31 and directly contradicts Eliphaz''s accusations that he stripped the naked', 'It is a general observation about Israelite poverty with no connection to Job''s personal ethics', 'It is an appeal for his friends to help the poor rather than argue with him', 'It introduces a new character — the poor wanderer — as a foil to Job''s former wealth', 'a', 'Job 24:7-8 — "They cause him to go naked without clothing, and they take away the sheaf from the hungry...They are wet with the showers of the mountains." This compassionate observation contradicts Eliphaz''s charge in Job 22:6-7 that Job stripped the naked and withheld bread.'),
('Job', 24, 'adults', 6, 'How does Job 24:18-24 relate to the friends'' position, and what is its literary function in Job''s speech?', 'Scholars debate whether these verses are Job''s ironic concession that eventually the wicked do perish — a nod to his friends'' position — or a sarcastic quotation of their views that Job then subverts by noting it is not the pattern he observes', 'The verses prove that Job ultimately agrees with Bildad and Eliphaz about divine retribution', 'The verses are a later scribal addition inserted to harmonise Job with Proverbs on the fate of the wicked', 'The verses represent Job''s shift toward repentance as he acknowledges God''s eventual justice', 'a', 'Job 24:18-24 — "He is swift as the waters...God hath given him to be in safety...They are exalted for a little while, but are gone." The tonal shift has led commentators to read these as either a concession or a citation of the friends'' theology, followed by Job''s qualification that observable reality does not confirm this pattern.'),
('Job', 24, 'adults', 7, 'What is the rhetorical force of Job''s final challenge in Job 24:25 — "if it be not so now, who will make me a liar, and make my speech nothing worth?"?', 'It is a direct challenge to the three friends to disprove his observations about the wicked prospering and the righteous suffering unjustly — an appeal to empirical reality over theological theory', 'It is an appeal to God to confirm Job''s speech by sending a sign from heaven', 'It is a legal oath invoking the elders of the city as arbiters of the dispute', 'It is a rhetorical surrender, acknowledging that no one can answer Job and therefore God must be unjust', 'a', 'Job 24:25 — "And if it be not so now, who will make me a liar, and make my speech nothing worth?" Job invites empirical refutation — his argument stands on observable reality, and he dares anyone to produce counter-evidence.'),
('Job', 24, 'adults', 8, 'How does Job chapter 24 as a whole advance the theodicy debate of the book beyond what has been argued in previous chapters?', 'It shifts the debate from Job''s personal suffering to a structural critique of divine governance — the systemic prosperity of the wicked and oppression of the poor — demanding an explanation of God''s inaction at a societal level', 'It retreats from theological argument to personal lament, marking a low point in Job''s faith', 'It introduces the concept of delayed retribution as Job''s own position, aligning him with the friends', 'It focuses entirely on personal sin rather than the broader question of divine justice in society', 'a', 'Job 24:1-12 moves from Job''s personal case to societal injustice — oppressed poor, murdered innocents, violated widows — asking why the omniscient God does not intervene. This broadens theodicy from individual to corporate, anticipating the divine speeches in Job 38-41 about God''s governance of creation.');

-- ═══ Job Chapter 25 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Job', 25, 'kids', 1, 'Who gives the short speech in Job chapter 25?', 'Bildad the Shuhite', 'Eliphaz the Temanite', 'Zophar the Naamathite', 'Elihu the Buzite', 'a', 'Job 25:1 — "Then answered Bildad the Shuhite, and said." This is Bildad''s third and final speech, the shortest speech in the dialogue.'),
('Job', 25, 'kids', 2, 'What did Bildad say about God''s armies?', 'Is there any number of his armies? and upon whom doth not his light arise?', 'His armies are mighty and none can count their shields', 'God''s armies stand watch over every mountain and valley', 'The angels of his armies are swift as eagles and strong as lions', 'a', 'Job 25:3 — "Is there any number of his armies? and upon whom doth not his light arise?"'),
('Job', 25, 'kids', 3, 'What did Bildad say even the moon and stars were not in God''s eyes?', 'The moon is not pure and the stars are not clean in his sight', 'The moon is dim compared to God''s glory and stars are like dust', 'The moon and stars hide their faces before the throne of God', 'The stars bow down before God and the moon is his footstool', 'a', 'Job 25:5 — "Behold even to the moon, and it shineth not; yea, the stars are not pure in his sight."'),
-- Teens
('Job', 25, 'teens', 1, 'What two attributes of God did Bildad emphasise at the opening of his speech?', 'Dominion and fear, with God making peace in his high places', 'Wisdom and power that none among men can comprehend', 'Justice and righteousness that go before his face', 'Holiness and glory that fill both heaven and earth', 'a', 'Job 25:2 — "Dominion and fear are with him, he maketh peace in his high places."'),
('Job', 25, 'teens', 2, 'What was Bildad''s central rhetorical question about man''s standing before God?', 'How then can man be justified with God? or how can he be clean that is born of a woman?', 'What must man do to stand before the Almighty and not be consumed?', 'Is there one among men who can answer God and stand upright before him?', 'Can the creature ever declare himself pure before his Creator?', 'a', 'Job 25:4 — "How then can man be justified with God? or how can he be clean that is born of a woman?"'),
('Job', 25, 'teens', 3, 'How did Bildad describe man compared to a worm?', 'How much less man, that is a worm, and the son of man, which is a worm', 'Man is lower than the crawling things and his wisdom is as the dust', 'The son of man is weaker than the worm that the birds devour', 'Man is but a worm before God and his days are as the grass', 'a', 'Job 25:6 — "How much less man, that is a worm? and the son of man, which is a worm?"'),
('Job', 25, 'teens', 4, 'What comparison did Bildad make between man and the moon in terms of purity?', 'Behold even to the moon, and it shineth not; and the stars are not pure in his sight — how much less man', 'The moon reflects God''s glory but man''s heart is darker than midnight', 'Man is as changeable as the moon and as cold as starlight', 'Even the full moon dims before God''s holiness — how then shall mortal man appear before him?', 'a', 'Job 25:5-6 — "Behold even to the moon, and it shineth not; yea, the stars are not pure in his sight. How much less man, that is a worm?"'),
('Job', 25, 'teens', 5, 'What is notable about the length of Bildad''s third speech compared to his earlier speeches?', 'It is extremely short — only six verses — suggesting he has run out of new arguments against Job', 'It is his longest speech because he summarises all the arguments of all three friends', 'It is the same length as his first speech, reflecting a deliberate literary symmetry', 'It is cut short because God interrupts the dialogue with a voice from the storm', 'a', 'Job 25 contains only 6 verses, making it the briefest speech in the entire dialogue. The progressive shortening of the friends'' speeches (Bildad: ch.8, ch.18, ch.25) mirrors the collapse of their retribution argument before Job''s relentless challenge.'),
-- Adults
('Job', 25, 'adults', 1, 'How does Bildad''s assertion "Dominion and fear are with him, he maketh peace in his high places" function as a rhetorical strategy against Job?', 'By emphasising God''s absolute sovereignty and the cosmic peace he maintains in heaven, Bildad implies that any challenge to God''s governance — such as Job''s lawsuit — is futile and impudent', 'Bildad is conceding Job''s point about divine hiddenness and redirecting the argument toward worship', 'The statement is a hymnic fragment inserted to soften the confrontational tone of the speech', 'Bildad is quoting a proverb about kings to establish an analogy for God''s court proceedings', 'a', 'Job 25:2 — "Dominion and fear are with him, he maketh peace in his high places." The rhetorical implication is: if God commands cosmic dominion and peace, who is Job to disturb that order with complaints?'),
('Job', 25, 'adults', 2, 'How does Bildad''s question "How then can man be justified with God?" (Job 25:4) echo earlier arguments in the book?', 'It echoes Eliphaz''s question in Job 4:17 — "Shall mortal man be more just than God?" — showing that the friends share a common theological framework of human unworthiness that they repeatedly deploy against Job', 'It introduces a new argument about forensic justification that goes beyond anything previously said', 'It directly quotes Zophar''s speech from chapter 11 as a summary of all three friends'' position', 'It is a unique formulation that marks Bildad''s distinct contribution to the theodicy debate', 'a', 'Job 25:4 — "How then can man be justified with God?" echoes Job 4:17 — "Shall mortal man be more just than God?" and Job 9:2 where Job himself asked the same question, showing the friends'' theology has made no progress in twenty-five chapters.'),
('Job', 25, 'adults', 3, 'What is the theological problem with Bildad''s argument from impurity in Job 25:4-6 as applied to Job''s situation?', 'While human creatureliness and impurity before God are theologically sound, Bildad misapplies the argument — the doctrine of universal human unworthiness cannot explain why one righteous person suffers more than others, which is Job''s actual question', 'Bildad''s argument is entirely valid and Job has no adequate response to it', 'The problem is that Bildad is teaching a doctrine of human depravity that was not yet revealed in Job''s era', 'The argument fails because Bildad does not cite any specific Mosaic law about impurity', 'a', 'Job 25:4-6 — universal human creatureliness before God is true, but it cannot account for differential suffering. Job does not claim to be God''s equal; he claims to be relatively righteous. Bildad''s argument is a category error.'),
('Job', 25, 'adults', 4, 'Why do scholars consider the abruptness of Bildad''s speech in Job 25 literarily significant?', 'Its brevity signals the rhetorical exhaustion of the three-friend tradition — they have nothing new to say, their arguments have been demolished by Job, and the dialogue effectively ends here with no third speech from Zophar', 'The brevity is accidental due to textual loss in manuscript transmission', 'The short speech shows Bildad is more humble than Eliphaz and Zophar', 'It marks the climax of the friends'' argument as Bildad states the final definitive word on Job''s guilt', 'a', 'Job 25 (6 verses) follows Bildad''s decreasing speech lengths (ch.8: 22v, ch.18: 21v, ch.25: 6v). Zophar gives no third speech at all. The progressive shrinkage mirrors the collapse of the friends'' case. Compare God''s verdict in Job 42:7.'),
('Job', 25, 'adults', 5, 'How does Bildad''s description of man as a "worm" in Job 25:6 compare to Job''s own language in Job 17:14?', 'Job had already used decay and worm language in Job 17:14 — "I have said to corruption, Thou art my father: to the worm, Thou art my mother" — but in the context of mortality, not moral unworthiness; Bildad weaponises the image against Job''s claim of innocence', 'Job''s worm language and Bildad''s are identical in meaning and function', 'Bildad is quoting Job''s own words back to him as evidence of self-condemnation', 'The two passages use different Hebrew words with unrelated meanings', 'a', 'Job 17:14 — "I have said to corruption, Thou art my father: to the worm, Thou art my mother." Job''s worm is the worm of the grave (physical mortality); Bildad''s in 25:6 is the worm of moral insignificance. Same image, contrasting arguments.'),
('Job', 25, 'adults', 6, 'What is ironic about Bildad''s claim that even the stars are not pure in God''s sight (Job 25:5) in light of Job 38:7?', 'In Job 38:7 God describes the morning stars singing together at creation — they are participants in worship, not merely impure creatures; Bildad''s reductionism strips the cosmos of the joy and worship that God''s own speech celebrates', 'There is no irony; Job 38:7 confirms Bildad''s point about cosmic impurity', 'The stars in Job 38:7 are impure angels whereas in Job 25 they are literal astronomical objects', 'The irony is that Bildad quotes a hymn that Job himself had sung in better days', 'a', 'Job 25:5 — "yea, the stars are not pure in his sight." Job 38:7 — "when the morning stars sang together, and all the sons of God shouted for joy?" God''s picture of creation is celebratory; Bildad''s is reductive — he uses transcendence to diminish rather than to wonder.'),
('Job', 25, 'adults', 7, 'What does the structural placement of Bildad''s brief speech immediately before Job''s extended response in chapters 26-31 achieve in the book''s rhetoric?', 'The contrast sets up Job''s triumphant multi-chapter response as a demolition of the friends'' enfeebled final argument; the brevity of Job''s opponent makes Job''s sustained eloquence all the more decisive', 'The placement shows that the friends'' argument is stronger than Job''s because brevity in wisdom literature implies greater authority', 'The placement mirrors the creation week, with short speeches representing rest and long speeches representing creative work', 'The contrast shows that both Job and Bildad are right, and their symmetrical placement balances the book''s argument', 'a', 'Bildad''s 6-verse speech (ch.25) is followed by Job''s 6-chapter response (chs.26-31). The structural imbalance itself is an argument — the friends are silenced; Job''s sustained, unanswered eloquence demonstrates the inadequacy of their position.'),
('Job', 25, 'adults', 8, 'How does Job''s later response in Job 26:2-4 directly mock Bildad''s speech in chapter 25?', 'Job sarcastically asks "How hast thou helped him that is without power? how savest thou the arm that hath no strength?" — directly addressing Bildad''s grand claims about God''s power as useless counsel to a man in Job''s condition', 'Job ignores Bildad''s speech entirely and addresses God instead', 'Job quotes Bildad''s speech approvingly before offering his own commentary on God''s power', 'Job thanks Bildad for his wisdom before explaining why it does not apply to his case', 'a', 'Job 26:2-4 — "How hast thou helped him that is without power? how savest thou the arm that hath no strength? How hast thou counselled him that hath no wisdom?" The sarcasm is direct: Bildad''s lofty theology about God''s dominion offered zero practical help to a suffering man.');

-- ═══ Job Chapter 26 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Job', 26, 'kids', 1, 'What remarkable thing did Job say God does with the earth that shows his great power?', 'He hangeth the earth upon nothing', 'He holds the earth in the palm of his hand', 'He sets the earth on pillars of silver', 'He balances the earth on the back of a great creature', 'a', 'Job 26:7 — "He stretcheth out the north over the empty place, and hangeth the earth upon nothing."'),
('Job', 26, 'kids', 2, 'What did Job say God does with the clouds so that they do not tear with the rain?', 'He bindeth up the waters in his thick clouds, and the cloud is not rent under them', 'He seals the clouds with his finger so no drop falls before the time', 'He sends the wind to hold the clouds in place above the mountains', 'He wraps the clouds around the earth like a garment', 'a', 'Job 26:8 — "He bindeth up the waters in his thick clouds; and the cloud is not rent under them."'),
('Job', 26, 'kids', 3, 'What did Job call the outer edges of what God has made and his power?', 'Lo, these are parts of his ways: but how little a portion is heard of him! but the thunder of his power who can understand?', 'The corners of the earth where light meets darkness', 'The great deep where no man has ever sailed', 'The mountains where God''s voice first echoed at creation', 'a', 'Job 26:14 — "Lo, these are parts of his ways: but how little a portion is heard of him! but the thunder of his power who can understand?"'),
-- Teens
('Job', 26, 'teens', 1, 'How did Job sarcastically respond to Bildad''s speech about God''s greatness?', 'How hast thou helped him that is without power? how savest thou the arm that hath no strength?', 'Dost thou think thy words of wisdom can comfort one who is afflicted as I am?', 'Art thou wiser than God that thou dost explain his ways to the suffering?', 'Hath not God already told thee these things in the secret of the night?', 'a', 'Job 26:2 — "How hast thou helped him that is without power? how savest thou the arm that hath no strength?"'),
('Job', 26, 'teens', 2, 'What did Job say about the realm of the dead and destruction before God?', 'Hell is naked before him, and destruction hath no covering', 'The gates of Sheol tremble at his voice and the dead hear his command', 'The pit has no bottom deep enough to hide from his gaze', 'The graves open at his word and the shades arise before him', 'a', 'Job 26:6 — "Hell is naked before him, and destruction hath no covering."'),
('Job', 26, 'teens', 3, 'What did Job say God did to the sea at creation by his power?', 'He smote through the proud; by his understanding he smiteth through Rahab', 'He divided the sea and walked through it on dry ground', 'He set the bounds of the sea and commanded it to be still', 'He poured the sea from the hollow of his hand into its basin', 'a', 'Job 26:12 — "He divideth the sea with his power, and by his understanding he smiteth through the proud."'),
('Job', 26, 'teens', 4, 'What did Job say about the pillars of heaven?', 'The pillars of heaven tremble and are astonished at his reproof', 'The pillars of heaven stand firm and will not move at the shaking of the earth', 'God set the pillars of heaven in the deep and none can uproot them', 'The pillars of heaven are the great mountains that hold up the sky', 'a', 'Job 26:11 — "The pillars of heaven tremble and are astonished at his reproof."'),
('Job', 26, 'teens', 5, 'What mythological creature did Job mention in connection with God''s power at sea?', 'Rahab', 'Leviathan', 'Behemoth', 'Tannin', 'a', 'Job 26:12 — "by his understanding he smiteth through the proud" — and v.13 — "his hand hath formed the crooked serpent." v.12 references "Rahab," a sea-chaos monster. Job 26:12 — "He divideth the sea with his power, and by his understanding he smiteth through the proud" — with Rahab explicitly named as the proud/sea monster.'),
-- Adults
('Job', 26, 'adults', 1, 'How does Job''s sarcasm in Job 26:2-4 serve his argument against Bildad?', 'Job exposes the futility of Bildad''s grand theological lecture by pointing out it offered no practical help to a powerless, suffering man — correct doctrine about God''s greatness is useless counsel without pastoral wisdom', 'Job is conceding Bildad''s theological point while disputing only his pastoral tone', 'Job is accusing Bildad of speaking by demonic rather than divine inspiration', 'Job is quoting Bildad''s own words back to him to show their internal contradiction', 'a', 'Job 26:2-4 — "How hast thou helped him that is without power?...Whose spirit came from thee?" The three rhetorical questions demolish the pretension that theological correctness equals pastoral usefulness.'),
('Job', 26, 'adults', 2, 'What is the cosmological significance of Job 26:7 — "he hangeth the earth upon nothing" — in the ancient Near Eastern context?', 'It is a remarkable statement of cosmic suspension with no material support, contrasting with surrounding cultures'' cosmologies that placed the earth on pillars, backs of animals, or cosmic waters — reflecting a uniquely elevated monotheistic cosmology', 'It is a poetic metaphor for God''s invisibility that has no cosmological claim', 'It reflects Babylonian science that Job had learned during his prosperity', 'It expresses Job''s uncertainty about the structure of creation during his suffering', 'a', 'Job 26:7 — "he hangeth the earth upon nothing." Ancient Near Eastern cosmologies (Mesopotamian, Egyptian) featured the earth supported by cosmic pillars or primordial water. Job''s formulation is theologically distinctive in attributing suspension to God''s power alone.'),
('Job', 26, 'adults', 3, 'What does Job''s description of God hiding the face of the throne and spreading his cloud over it (Job 26:9) contribute to the book''s theology of divine hiddenness?', 'It develops a cosmic counterpart to Job''s personal experience of God''s hiddenness — even God''s own throne is veiled; hiddenness is not a sign of divine absence but of divine transcendence', 'It is a description of a thunderstorm that Job observed during his prosperity', 'It contradicts Job''s earlier wish to find God and come to his seat (ch.23)', 'It supports Bildad''s argument that God is too high to concern himself with Job', 'a', 'Job 26:9 — "He holdeth back the face of his throne, and spreadeth his cloud upon it." The veiled throne echoes Job 23''s search for God — even heaven does not give unmediated access to the divine presence. Hiddenness is woven into the nature of God, not a personal judgment on Job.'),
('Job', 26, 'adults', 4, 'How does Job''s reference to Rahab in Job 26:12 function within the broader use of chaos-monster imagery in the book?', 'Rahab represents primordial chaos that God subdued at creation; Job invokes this to demonstrate God''s supreme power over the forces of disorder, which also raises the implicit question of why that same power allows Job''s unjust suffering', 'Rahab is a historical reference to the woman of Jericho who hid the spies', 'Rahab is used to illustrate the wickedness of Job''s enemies who have conspired against him', 'The reference is purely decorative mythological language with no theological weight', 'a', 'Job 26:12 — "he smiteth through the proud" (Rahab, lit. "the Proud One") is the sea-chaos monster of ancient Near Eastern mythology (cf. Ps 89:10, Isa 51:9). Job uses creation-myth language to magnify God''s power — the same power that bafflingly does not intervene for him.'),
('Job', 26, 'adults', 5, 'What is the rhetorical purpose of the crooked serpent in Job 26:13 in the context of Job''s self-defence?', 'Job describes God forming the crooked serpent to demonstrate that even the most powerful and chaotic creature is subject to God''s creative hand, amplifying his portrait of a God whose power is total — and therefore whose apparent inaction with Job is a genuine mystery', 'The crooked serpent is a reference to Satan who has afflicted Job, and Job is warning God about him', 'The serpent is a symbol of Job''s own spiritual condition as a sinner needing redemption', 'Job uses the serpent to threaten his friends with divine punishment if they continue their false accusations', 'a', 'Job 26:13 — "his hand hath formed the crooked serpent." The serpent (nachash bariach) echoes Isa 27:1 (Leviathan). Job''s hymn to God''s creative power is also an implicit challenge: the God who commands these forces surely has the power to act justly — yet remains silent.'),
('Job', 26, 'adults', 6, 'What does Job 26:14 — "but the thunder of his power who can understand?" — contribute to the book''s epistemology?', 'It establishes that human knowledge of God is inherently partial — what can be observed and described ("parts of his ways") is only a whisper compared to God''s full reality, preparing for the divine speeches in chapters 38-41 that confirm this epistemological humility', 'It is an admission that Job himself cannot understand God and therefore should stop arguing', 'It concedes Bildad''s point that God''s power is incomprehensible and men should be silent before him', 'It expresses despair that God will never reveal himself to Job or answer his questions', 'a', 'Job 26:14 — "Lo, these are parts of his ways: but how little a portion is heard of him! but the thunder of his power who can understand?" This epistemological humility is genuine — and it is Job who states it, not the friends, anticipating God''s own argument in chs.38-41.'),
('Job', 26, 'adults', 7, 'How does Job''s description of God''s control over the dawn, the sea, and death in Job 26:5-13 exceed what Bildad said in chapter 25?', 'Where Bildad made two brief points (dominion/fear and human creatureliness), Job gives a sustained, detailed, and more magnificent hymn to God''s cosmic power, demonstrating that he knows God''s greatness better than his friends do', 'Bildad''s speech is theologically superior; Job is merely being more verbose about the same points', 'Job''s chapter 26 is a rebuke of God''s power rather than a celebration of it', 'Job is quoting a hymn that Bildad taught him during their earlier friendship', 'a', 'Job 25 covers God''s dominion and human creatureliness in 6 verses. Job 26 covers the underworld (v.5-6), cosmos (v.7-9), clouds and thunder (v.8-10), pillars of heaven (v.11), sea/Rahab/crooked serpent (v.12-13) — a richer and more detailed doxology, showing Job''s theology is not inferior to his friends''.'),
('Job', 26, 'adults', 8, 'What is the theological paradox that Job''s hymn in chapter 26 creates for the book''s argument as a whole?', 'Job praises God''s immense, cosmos-ordering power while simultaneously demanding an explanation for God''s silence — the very power he praises could relieve his suffering but does not, making God''s inaction more, not less, mysterious', 'The hymn resolves all paradox by showing God''s power is a sufficient explanation for suffering', 'The paradox is resolved by Job''s conclusion that he is not worthy of God''s attention', 'There is no paradox — the hymn is simply a concession before Job renews his complaint', 'a', 'Job 26:7-14 magnifies God''s power; Job 23:3-5 cries for access to that same God. The juxtaposition is the book''s central theological tension: an all-powerful God who both rules the cosmos and remains hidden from the sufferer who loves him.');

-- ═══ Job Chapter 27 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Job', 27, 'kids', 1, 'What did Job refuse to give up throughout his suffering?', 'My righteousness I hold fast, and will not let it go', 'My hope in God who will one day restore me', 'My prayer that God would show himself to me', 'My faith that God would send a redeemer for me', 'a', 'Job 27:6 — "My righteousness I hold fast, and will not let it go: my heart shall not reproach me so long as I live."'),
('Job', 27, 'kids', 2, 'What did Job say about people who forget God?', 'What is the hope of the hypocrite, though he hath gained, when God taketh away his soul?', 'Those who forget God shall wander in the wilderness', 'They shall not find peace though they search the earth over', 'God shall turn his face from them and they shall be alone', 'a', 'Job 27:8 — "For what is the hope of the hypocrite, though he hath gained, when God taketh away his soul?"'),
('Job', 27, 'kids', 3, 'What happens to the wicked man''s house in the storm, according to Job?', 'The east wind carrieth him away, and he departeth; a storm hurleth him out of his place', 'His house is burned with fire and his walls fall to the ground', 'He is buried under the sand when the great winds come', 'Floodwaters rise and sweep away all he has built', 'a', 'Job 27:21 — "The east wind carrieth him away, and he departeth: and as a storm hurleth him out of his place."'),
-- Teens
('Job', 27, 'teens', 1, 'What oath did Job swear regarding his integrity?', 'As God liveth, who hath taken away my judgment, the Almighty who hath vexed my soul', 'I swear before heaven and earth that my heart is clean before my Maker', 'As the LORD liveth, I will hold my integrity until I draw my last breath', 'By the life of the Almighty I will not speak falsehood against my own soul', 'a', 'Job 27:2 — "As God liveth, who hath taken away my judgment; and the Almighty, who hath vexed my soul." Job''s oath is striking — he swears by the very God he accuses of wronging him.'),
('Job', 27, 'teens', 2, 'What did Job say his lips would not speak even in his suffering?', 'My lips shall not speak wickedness, nor my tongue utter deceit', 'My mouth shall not curse God even though he hath afflicted me', 'My tongue shall not confess sins that I have not committed', 'My lips shall not ask for death though my suffering is great', 'a', 'Job 27:4 — "My lips shall not speak wickedness, nor my tongue utter deceit."'),
('Job', 27, 'teens', 3, 'What did Job say the wicked man''s children would face?', 'His children shall be multiplied, but it is for the sword; and his offspring shall not be satisfied with bread', 'His sons shall be scattered and his daughters taken into captivity', 'His children shall bury him in shame and inherit only his debts', 'They shall grow up as orphans and no man shall pity them', 'a', 'Job 27:14 — "If his children be multiplied, it is for the sword: and his offspring shall not be satisfied with bread."'),
('Job', 27, 'teens', 4, 'What happens to the silver and fine clothing that the wicked man stores up?', 'Though he heap up silver as the dust and prepare raiment as the clay, the just shall put it on, and the innocent shall divide the silver', 'His silver shall melt in the fires of judgment and his clothing shall rot', 'His children shall sell his silver to pay his debts', 'His silver shall be taken by the king as tribute', 'a', 'Job 27:16-17 — "Though he heap up silver as the dust, and prepare raiment as the clay; He may prepare it, but the just shall put it on, and the innocent shall divide the silver."'),
('Job', 27, 'teens', 5, 'What did Job say the wicked man builds that others will inhabit?', 'He buildeth his house as a moth, and as a booth that the keeper maketh', 'He constructs a palace of cedar but cannot live to see it finished', 'He lays foundations of stone but the righteous shall dwell therein', 'He builds high towers but they fall before the east wind', 'a', 'Job 27:18 — "He buildeth his house as a moth, and as a booth that the keeper maketh."'),
-- Adults
('Job', 27, 'adults', 1, 'What is the theological significance of Job swearing by "God who hath taken away my judgment" in Job 27:2?', 'Job swears by the very God he believes has wronged him — acknowledging God''s existence and authority even while accusing him of injustice; this is a profound act of simultaneous faith and protest', 'Job''s oath shows he has lost faith in God''s justice and is appealing to raw divine power', 'The oath is a legal formula that invokes God as witness without any theological statement about God''s character', 'Job is swearing by God as a way of pressuring God to respond to his case', 'a', 'Job 27:2 — "As God liveth, who hath taken away my judgment; and the Almighty, who hath vexed my soul." The paradox — swearing by the God who has wronged you — is the essence of Job''s faith: he cannot abandon God even when God appears unjust.'),
('Job', 27, 'adults', 2, 'What does Job''s declaration "my heart shall not reproach me so long as I live" (Job 27:6) reveal about his understanding of conscience?', 'It shows Job grounds his assurance in the verdict of a clear conscience — a form of internal moral testimony that operates independently of external religious opinion and friends'' accusations', 'It is an arrogant claim that Job has never sinned in thought, word, or deed', 'It shows Job has become indifferent to God''s judgment because his conscience has become seared', 'It is a legal statement that Job had never been formally convicted by the city elders', 'a', 'Job 27:6 — "My righteousness I hold fast, and will not let it go: my heart shall not reproach me so long as I live." The conscience as internal moral witness anticipates NT conscience theology (cf. 1 John 3:20-21) and is Job''s deepest defence.'),
('Job', 27, 'adults', 3, 'Why does Job describe the fate of the wicked in terms similar to what his friends said about him, and what is the ironic implication?', 'By showing he knows the traditional doctrine of retribution perfectly well, Job makes clear he is not ignorant of it — his complaint is precisely that this doctrine does not match his reality, even though he is innocent', 'Job is finally conceding that his friends were right and that he has been wicked', 'Job is applying the friends'' doctrine to them personally as a veiled threat', 'Job is distinguishing between the wicked who suffer in this life and those who suffer after death', 'a', 'Job 27:13-23 uses retribution language virtually identical to his friends'' speeches. By deploying the friends'' own argument perfectly, Job shows he knows it — and then in chs.23-24 shows it does not match observable reality, making the irony devastating.'),
('Job', 27, 'adults', 4, 'What does Job''s description of the hypocrite''s hope in Job 27:8-10 reveal about his theology of prayer?', 'Job argues that the hypocrite''s hope is hollow because in crisis he cannot cry to God — not from inability but from a lack of genuine relationship; true prayer requires an authentic connection with God that the godless do not possess', 'Job is claiming that prayer is only valid when offered in prosperity', 'Job is saying that God refuses to hear the prayers of anyone who has sinned', 'Job is arguing that the hypocrite will eventually cry to God and be heard at the last moment', 'a', 'Job 27:9-10 — "Will God hear his cry when trouble cometh upon him? Will he delight himself in the Almighty? will he always call upon God?" The rhetorical questions imply no — the hypocrite has no relational access to God in prayer, unlike Job who cries to God throughout.'),
('Job', 27, 'adults', 5, 'What does the image of the wicked man''s house as "a moth" in Job 27:18 contribute to Job''s portrait of retribution?', 'The moth-built house is an image of fragility — something constructed with great effort but inherently impermanent and quickly destroyed — showing that the wicked man''s wealth and security are structurally unsound', 'The moth image refers to insects destroying the wicked man''s stored garments', 'Job is saying the wicked man builds as quickly and carelessly as a moth', 'The moth image is borrowed from Proverbs and has no specific meaning in Job''s argument', 'a', 'Job 27:18 — "He buildeth his house as a moth, and as a booth that the keeper maketh." A moth''s cocoon is temporary; a harvest booth (sukkah) is seasonal. The wicked man''s apparently solid wealth is structurally temporary.'),
('Job', 27, 'adults', 6, 'How does the east wind in Job 27:21 function as a divine instrument of judgment?', 'The east wind (qadim) in Hebrew imagery is a hot, devastating sirocco wind from the desert that destroys crops and overwhelms the unprepared; its use here implies that God''s judgment on the wicked comes suddenly and irresistibly', 'The east wind is simply a weather metaphor with no theological significance in the Hebrew Bible', 'The east wind represents the armies of the Babylonians who will one day punish the wicked', 'Job borrowed the east wind imagery from Egyptian cosmology to describe divine punishment', 'a', 'Job 27:21 — "The east wind carrieth him away, and he departeth: and as a storm hurleth him out of his place." The east wind (qadim) appears in divine judgment contexts throughout the Hebrew Bible (Jer 18:17, Ezek 27:26, Hos 13:15) as a destroying force.'),
('Job', 27, 'adults', 7, 'What is the significance of terrors overtaking the wicked like waters in Job 27:20?', 'Job uses the flood imagery of overwhelming disaster to show that the wicked man''s end is sudden and total — terrors and waters combined evoke a complete loss of control that mirrors the friends'' description of Job''s own experience, reinforcing Job''s ironic use of their doctrine', 'The image of waters refers to literal flooding of the wicked man''s fields as divine punishment', 'Job is alluding to the flood of Noah as the prototype of divine judgment on the wicked', 'The terrors like waters are the nightmares that torment the wicked in their sleep', 'a', 'Job 27:20 — "Terrors take hold on him as waters, a tempest stealeth him away in the night." The friends used similar imagery to describe Job''s supposed guilt (Bildad, ch.18:11 — "Terrors shall make him afraid on every side"). Job now shows this applies to the actually wicked.'),
('Job', 27, 'adults', 8, 'How does Job chapter 27 resolve the tension between Job''s moral innocence and his continued suffering, theologically?', 'It does not resolve the tension — Job holds both truths simultaneously: his own righteousness (v.2-6) and the doctrine that the wicked are eventually punished (v.13-23), but refuses to collapse either truth to relieve the cognitive dissonance, which is itself the mark of his integrity', 'The tension is resolved by Job admitting a small sin in verse 7', 'The tension is resolved when Job accepts that retribution is delayed but certain', 'Job resolves the tension by arguing that suffering purifies the righteous into something greater', 'a', 'Job 27:2-6 — his own innocence; Job 27:13-23 — the wicked do eventually suffer. Both true. Neither resolves Job''s case. The unresolved tension carries forward to God''s answer in chapters 38-41, which does not explain the suffering but restores the relationship.');

-- ═══ Job Chapter 28 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Job', 28, 'kids', 1, 'What is the great question asked in the wisdom poem of Job chapter 28?', 'But where shall wisdom be found? and where is the place of understanding?', 'Who is wise enough to stand before the LORD and live?', 'Which of all God''s creatures is the wisest that ever was made?', 'Can a man find wisdom if he searches the whole earth over?', 'a', 'Job 28:12 — "But where shall wisdom be found? and where is the place of understanding?"'),
('Job', 28, 'kids', 2, 'Can wisdom be bought with gold or silver?', 'No, it cannot be gotten for gold, neither shall silver be weighed for the price thereof', 'Yes, if a man gives all his gold he may buy a little wisdom', 'Only the king can buy wisdom with his royal treasure', 'Wisdom costs nothing but must be learned from the elders of the city', 'a', 'Job 28:15 — "It cannot be gotten for gold, neither shall silver be weighed for the price thereof."'),
('Job', 28, 'kids', 3, 'What did God say is wisdom?', 'The fear of the Lord, that is wisdom; and to depart from evil is understanding', 'Keeping the commandments and honouring thy father and mother', 'Searching the scriptures and praying every morning', 'Giving to the poor and caring for the widow and orphan', 'a', 'Job 28:28 — "And unto man he said, Behold, the fear of the Lord, that is wisdom; and to depart from evil is understanding."'),
-- Teens
('Job', 28, 'teens', 1, 'What did Job describe miners doing to find precious stones in the earth?', 'Man putteth forth his hand upon the rock; he overturneth the mountains by the roots and he cutteth out rivers among the rocks', 'Men dig great trenches in the earth and lower themselves down on ropes', 'They search the riverbeds for gold and the seashores for precious coral', 'They break the mountains with iron and pour hot water over the rock to find gems', 'a', 'Job 28:9-10 — "He putteth forth his hand upon the rock; he overturneth the mountains by the roots. He cutteth out rivers among the rocks; and his eye seeth every precious thing."'),
('Job', 28, 'teens', 2, 'What does Job say the path to wisdom is hidden from?', 'It is hid from the eyes of all living, and kept close from the fowls of the air', 'It is hidden from children and the foolish who do not seek it', 'It is sealed in the depths of the sea where no ship can sail', 'It is locked in the chambers of heaven where only angels dwell', 'a', 'Job 28:21 — "Seeing it is hid from the eyes of all living, and kept close from the fowls of the air."'),
('Job', 28, 'teens', 3, 'What two precious things did Job say wisdom surpasses in value?', 'The gold of Ophir and the precious onyx, and the sapphire', 'Rubies from the east and diamonds from the deep mines', 'The finest silver of Tarshish and the ivory of the great sea', 'Pearls from the sea and purple cloth from the house of kings', 'a', 'Job 28:16 — "It cannot be valued with the gold of Ophir, with the precious onyx, or the sapphire."'),
('Job', 28, 'teens', 4, 'What did Job say the sea and the deep say about wisdom?', 'The deep saith, It is not in me: and the sea saith, It is not with me', 'The sea whispers of wisdom to those who listen at the shore at dawn', 'The deep guards wisdom in its lowest places and will not give it up', 'The sea and the deep were created before wisdom and know nothing of it', 'a', 'Job 28:14 — "The depth saith, It is not in me: and the sea saith, It is not with me."'),
('Job', 28, 'teens', 5, 'How did God come to know wisdom according to Job 28:27?', 'Then did he see it, and declare it; he prepared it, yea, and searched it out', 'God breathed wisdom into the earth at the beginning of creation', 'He revealed it to the angels first and then to man at the dawn of time', 'He placed wisdom in the law and made it available to all who would seek it', 'a', 'Job 28:27 — "Then did he see it, and declare it; he prepared it, yea, and searched it out."'),
-- Adults
('Job', 28, 'adults', 1, 'What literary function does the wisdom poem of Job 28 serve in the overall structure of the book?', 'It provides a structural interlude between the dialogue (chs.3-27) and Job''s final defence (chs.29-31), raising the epistemological question of where wisdom is found before God''s answer in chs.38-41 implicitly responds', 'It is Job''s admission that he does not have wisdom and therefore cannot argue with God', 'It is a hymn composed by the narrator to break the tension between Job and his friends', 'It is Zophar''s missing third speech inserted here by a later editor', 'a', 'Job 28 stands apart from the dialogue — no speech formula introduces it. Its question "where shall wisdom be found?" (v.12) is answered by God''s whirlwind speeches which show wisdom is displayed in creation and belongs to God, not to human theological systems.'),
('Job', 28, 'adults', 2, 'What does Job 28:1-11 teach about the nature of human technological achievement versus the limits of human wisdom?', 'Man demonstrates extraordinary ingenuity in mining precious metals and gems from the depths of the earth, yet this same technological brilliance cannot locate wisdom — showing that technical mastery does not equal moral or divine wisdom', 'Job is condemning the mining industry as an example of human greed and exploitation', 'The mining description shows that man can find anything he searches for diligently enough, including wisdom', 'Job is contrasting the value of natural resources with the worthlessness of philosophical speculation', 'a', 'Job 28:1-11 details man''s mining feats: shafts, lamps underground, hanging on ropes, turning over mountains. Yet v.12-13 — "But where shall wisdom be found?...Man knoweth not the price thereof." Human capability reaches its limit precisely where wisdom begins.'),
('Job', 28, 'adults', 3, 'How does the refrain "it cannot be gotten for gold" in Job 28:15 challenge the ancient world''s equation of wisdom with wealth and social power?', 'It declares wisdom''s incommensurability with any commercial value — even the greatest treasures of the ancient world (gold of Ophir, sapphires, onyx) are insufficient currency for wisdom, placing it entirely outside market or social acquisition', 'The refrain is a warning against materialism in general rather than a statement about wisdom specifically', 'Job is quoting a wisdom school proverb about the limits of material wealth', 'The refrain means that wisdom is free and available to everyone who asks', 'a', 'Job 28:15-19 lists gold, silver, gold of Ophir, onyx, sapphire, crystal, coral, pearls, rubies, Ethiopian topaz — the entire catalogue of ancient luxury — and declares each insufficient. Wisdom is beyond the economy of exchange.'),
('Job', 28, 'adults', 4, 'What does the personification of the deep and the sea saying "It is not in me" (Job 28:14) contribute to the poem''s argument?', 'It shows that wisdom is not hidden in any created realm — neither the sky, the sea, the deep, nor the land of the living — and can only be located where God has placed it, reinforcing God''s unique proprietorship of wisdom', 'It shows that wisdom was not present at creation and was added to the world later', 'Job is drawing on Canaanite mythology about Yam (sea) and Tehom (deep) as rival powers', 'The personification is purely poetic with no theological argument about the nature of wisdom', 'a', 'Job 28:14 — "The depth saith, It is not in me: and the sea saith, It is not with me." The cosmic sweep — Abaddon (v.22), Death (v.22), the deep, the sea — creates an exhaustive inventory of created realms, all of which lack wisdom. Only God has it (v.23).'),
('Job', 28, 'adults', 5, 'What is the theological relationship between God''s creative work described in Job 28:23-26 and his knowledge of wisdom?', 'God''s knowledge of wisdom is demonstrated through and inseparable from his creative work — he saw wisdom when he measured the winds and waters, established the weight of the winds, and set limits for the rain, showing wisdom is embedded in the structure of creation itself', 'God learned wisdom from wisdom that pre-existed creation as an independent cosmic principle', 'God hid wisdom inside creation so that man could find it through scientific investigation', 'God used wisdom as a tool of creation but then placed it beyond creation so no creature could access it', 'a', 'Job 28:25-27 — "To make the weight for the winds; and he weigheth the waters by measure...Then did he see it, and declare it; he prepared it, yea, and searched it out." God''s wisdom is manifest in creation''s precise ordering — anticipating Job 38:4-7.'),
('Job', 28, 'adults', 6, 'How does the conclusion of Job 28 — "the fear of the Lord, that is wisdom; and to depart from evil is understanding" — relate to the prologue''s description of Job in Job 1:1?', 'Job 1:1 describes Job as "one that feared God, and eschewed evil" — exactly the twin definitions of wisdom in Job 28:28 — establishing that Job already possessed the wisdom that the poem declares only God can bestow', 'The conclusion shows Job had not yet attained wisdom at the start of the book and that his suffering was meant to teach him', 'The connection is coincidental since fear of God is a common phrase in wisdom literature', 'The conclusion is added to harmonise the poem with Proverbs 1:7 and has no connection to Job''s character', 'a', 'Job 1:1 — "feared God, and eschewed evil." Job 28:28 — "the fear of the Lord, that is wisdom; and to depart from evil is understanding." The verbal parallel is deliberate — Job is introduced as a living embodiment of wisdom''s definition, making his suffering the book''s central paradox.'),
('Job', 28, 'adults', 7, 'Why is the placement of the wisdom poem after the dialogue but before Job''s final defence (chapters 29-31) significant for the reader''s interpretation of Job''s subsequent speeches?', 'It primes the reader to evaluate Job''s self-defence in chs.29-31 not as arrogance but as wisdom — specifically, as the outworking of the fear of God and departure from evil that ch.28 identifies as the only human access to wisdom', 'It shows that Job has not yet learned wisdom and his self-defence in ch.29-31 is therefore flawed', 'It positions the wisdom poem as a divine interruption that silences Job before he can continue arguing', 'It has no structural function and is an independent fragment loosely attached to the book', 'a', 'Job 28:28 defines wisdom as fearing God and departing from evil. Job 29-31 then demonstrates exactly those qualities — his past integrity (ch.29-30) and his oath of innocence (ch.31). The poem frames what follows as wisdom in action, not as pride.'),
('Job', 28, 'adults', 8, 'How does Job 28 anticipate God''s response to Job in the divine speeches of chapters 38-41?', 'Job 28 asks where wisdom is found and answers: only God knows; God''s whirlwind speeches then demonstrate wisdom in the created order — the questions about foundations of the earth, sea, light, weather, and animals all show wisdom embedded in creation, fulfilling the poem''s implicit promise', 'Job 28 is answered by God by pointing Job to wisdom literature such as Proverbs', 'God''s speeches contradict Job 28 by showing wisdom is accessible to all who observe nature carefully', 'Job 28 asks a question that God deliberately refuses to answer in the divine speeches', 'a', 'Job 28:12 — "where shall wisdom be found?" Job 38:4 — "Where wast thou when I laid the foundations of the earth?" God''s speech tours the same cosmic terrain as Job 28 — weather, sea, stars, animals — and implicitly answers: wisdom is displayed here, in creation, and belongs to God alone.');

-- ═══ Job Chapter 29 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Job', 29, 'kids', 1, 'What did Job wish would come back to him when he thought about the old days?', 'Oh that I were as in months past, as in the days when God preserved me', 'That his children would come back and sit at his table', 'That his cattle would return to graze in his fields', 'That the sun would shine as brightly as when he was young', 'a', 'Job 29:2 — "Oh that I were as in months past, as in the days when God preserved me."'),
('Job', 29, 'kids', 2, 'What did Job wear like clothing in the old days?', 'I put on righteousness, and it clothed me: my judgment was as a robe and a diadem', 'He wore fine linen robes that his servants wove for him', 'He put on the armour of God each morning before going to the gate', 'He dressed in purple as a sign that God had blessed him greatly', 'a', 'Job 29:14 — "I put on righteousness, and it clothed me: my judgment was as a robe and a diadem."'),
('Job', 29, 'kids', 3, 'What did Job do for the poor and the fatherless in his days of blessing?', 'I was a father to the poor: and the cause which I knew not I searched out', 'He built houses for the homeless and gave bread to the hungry', 'He paid the debts of the poor and freed those in prison', 'He taught the children of the fatherless to read and to pray', 'a', 'Job 29:16 — "I was a father to the poor: and the cause which I knew not I searched out."'),
-- Teens
('Job', 29, 'teens', 1, 'How did Job describe God''s blessing on him in the autumn of his former days?', 'When his candle shined upon my head, and when by his light I walked through darkness', 'God''s hand was upon me and none could stand against me in the gate', 'The blessing of God covered my house like a cloud and my flocks multiplied', 'God''s voice spoke to me in the morning and his peace filled my house', 'a', 'Job 29:3 — "When his candle shined upon my head, and when by his light I walked through darkness."'),
('Job', 29, 'teens', 2, 'How did Job describe the respect he received from the young and the elders at the city gate?', 'The young men saw me, and hid themselves: and the aged arose, and stood up', 'The elders rose and gave me the seat of honour and the young men praised me', 'Men stepped aside when they saw me coming and bowed their heads in honour', 'The princes ceased speaking and the nobles held their peace when I appeared', 'a', 'Job 29:8 — "The young men saw me, and hid themselves: and the aged arose, and stood up."'),
('Job', 29, 'teens', 3, 'What did Job do for those who were dying and widows?', 'I delivered the poor that cried, and the fatherless, and him that had none to help him', 'He built a storehouse of grain for widows and paid a physician for the sick', 'He appointed servants to care for widows and scribes to write their petitions', 'He held feasts for the dying and distributed his silver to the needy', 'a', 'Job 29:12 — "Because I delivered the poor that cried, and the fatherless, and him that had none to help him."'),
('Job', 29, 'teens', 4, 'What did Job say the blessing of those who were ready to perish came to him?', 'The blessing of him that was ready to perish came upon me: and I caused the widow''s heart to sing for joy', 'Their prayers ascended before God and were answered for Job''s sake', 'Men spoke of my good deeds even in distant lands and kings sent messengers', 'The gratitude of the needy was stored up for me as gold in the treasury of heaven', 'a', 'Job 29:13 — "The blessing of him that was ready to perish came upon me: and I caused the widow''s heart to sing for joy."'),
('Job', 29, 'teens', 5, 'What image did Job use for how he expected to die peacefully before his trials came?', 'I shall die in my nest, and I shall multiply my days as the sand', 'I thought I would lie down with my fathers in the cave of Machpelah', 'I expected to grow old as a tree planted by rivers of water', 'I believed I would sleep the sleep of the righteous without pain or sorrow', 'a', 'Job 29:18 — "Then I said, I shall die in my nest, and I shall multiply my days as the sand."'),
-- Adults
('Job', 29, 'adults', 1, 'What is the rhetorical function of Job chapter 29 as the opening of Job''s final defence (chs.29-31)?', 'It establishes the contrast between his glorious past and present misery, creating the pathos necessary for his oath of innocence in ch.31 — the greatness of what has been lost makes the unjustness of the suffering more acute', 'It is a nostalgic digression with no argumentative function in Job''s defence', 'It is Job''s concession that his past prosperity was the evidence of God''s favour that his friends claimed', 'It establishes Job as a great man so that the reader will sympathise with his request for death in ch.3', 'a', 'Job 29 (past glory) + Job 30 (present shame) + Job 31 (oath of innocence) form a triptych: the greater the former glory, the more scandalous the present degradation, and the more powerful the sworn innocence of ch.31.'),
('Job', 29, 'adults', 2, 'What does "when his candle shined upon my head, and when by his light I walked through darkness" (Job 29:3) reveal about Job''s understanding of his former relationship with God?', 'It presents God''s presence as personal illumination — a light that guided Job through difficulties and was experienced as divine favour and closeness, making God''s current hiddenness (ch.23) all the more painful by contrast', 'It is a reference to the Urim and Thummim that priests used for divine guidance', 'It shows Job believed God''s blessing was purely material — light standing for wealth and prosperity', 'It is a metaphor for Job''s own natural wisdom that he mistakenly attributed to God', 'a', 'Job 29:3 — "his candle shined upon my head...by his light I walked through darkness." The light-of-divine-presence motif contrasts with Job''s current darkness (ch.30:26 — "I looked for light, there came darkness"). God''s absence is experienced as extinguished light.'),
('Job', 29, 'adults', 3, 'How does Job''s description of his social authority at the gate in Job 29:7-10 function as counter-evidence to Eliphaz''s accusations in chapter 22?', 'Job''s description of the community''s voluntary deference — princes ceasing to speak, nobles holding their peace — demonstrates the social capital earned by genuine righteousness, directly countering Eliphaz''s fabricated accusations that Job oppressed the poor', 'Job is boasting about social status to shame his friends who have no comparable authority', 'The gate description is a literary convention with no connection to Eliphaz''s specific accusations', 'Job is showing that his social position excuses whatever sins Eliphaz accused him of', 'a', 'Job 29:7-10 — "The young men saw me, and hid themselves: and the aged arose...The princes refrained talking...The nobles held their peace." Compare Eliphaz''s accusation in Job 22:8 — "the mighty man, he had the earth." The deference was earned, not seized.'),
('Job', 29, 'adults', 4, 'What is the theological significance of Job''s claim "I put on righteousness, and it clothed me" (Job 29:14)?', 'Righteousness as garment imagery presents moral integrity as an identity-constituting reality that defines Job''s whole person — his judicial and ethical character was as natural and visible as clothing, not merely occasional right acts', 'The clothing metaphor shows Job performed public righteousness for the sake of social reputation', 'Job is describing the priestly robes he wore as a civic religious leader in Uz', 'The metaphor shows righteousness was an external covering for Job''s internal sinfulness', 'a', 'Job 29:14 — "I put on righteousness, and it clothed me: my judgment was as a robe and a diadem." The garment/diadem metaphors present righteousness and justice as inseparable from Job''s identity — this is what makes the charge of sin from the friends so devastating to him.'),
('Job', 29, 'adults', 5, 'What does Job''s statement "I caused the widow''s heart to sing for joy" (Job 29:13) establish in anticipation of his oath in chapter 31?', 'It establishes a positive legacy of concrete social righteousness that directly refutes Eliphaz''s charge in Job 22:9 — "Thou hast sent widows away empty" — creating an evidentiary foundation for the oath of innocence', 'It is a general claim of generosity with no connection to the specific accusations of chapter 22', 'It shows Job''s motivation was personal honour rather than genuine care for widows', 'It anticipates Job''s vision of future restoration in which he will help widows again', 'a', 'Job 22:9 — "Thou hast sent widows away empty." Job 29:13 — "I caused the widow''s heart to sing for joy." The direct contrast is intentional — Job''s memory is the positive evidence that he is building toward his formal oath in ch.31.'),
('Job', 29, 'adults', 6, 'What does Job 29:18 — "I shall die in my nest, and I shall multiply my days as the sand" — reveal about his pre-affliction theodicy?', 'It reveals that Job shared the conventional wisdom assumption that righteousness guarantees a peaceful, long death — the very assumption his suffering has demolished, making his book-long argument not simply personal complaint but a crisis of his former theology', 'It shows Job was arrogantly complacent before his suffering began', 'It is a poetic image for Job''s expectation of reincarnation or afterlife', 'It demonstrates that Job always doubted God and expected prosperity to end', 'a', 'Job 29:18-20 shows Job''s former expectation of peaceful death, renewing strength, and his bow remaining fresh. His affliction has not only taken his prosperity — it has shattered his operative worldview. The book is his working through that collapse.'),
('Job', 29, 'adults', 7, 'How does Job 29:21-23 describe his former social authority as a teacher and adviser?', 'Men waited for him, kept silence for his counsel, opened their mouths wide to receive his words as the spring rain — presenting Job as a sage whose wisdom was eagerly received like life-giving moisture', 'Job describes himself as a judge who passed binding legal verdicts at the city gate', 'He portrays himself as a prophet whose words were taken as divine oracle', 'Job presents himself as a king whose commands were carried out without question', 'a', 'Job 29:21-23 — "Unto me men gave ear, and waited, and kept silence at my counsel...they waited for me as for the rain; and they opened their mouth wide as for the latter rain." The rain imagery presents wisdom as nourishment — his words were life-giving to those who heard them.'),
('Job', 29, 'adults', 8, 'What is the relationship between Job''s self-description in chapter 29 and the Servant of the LORD imagery in Isaiah 53?', 'Both figures are described as righteous and beneficial to others (Job: helping the poor, blind, lame; Isaiah''s Servant: bearing others'' griefs) yet suffer unjustly, suggesting that the Joban tradition contributes to the Hebrew Bible''s developing theology of innocent suffering', 'The parallel is superficial since Job is a historical figure and the Servant is a prophetic symbol', 'Job chapter 29 is directly quoted in Isaiah 53 as a type of the Suffering Servant', 'The relationship is only in the use of clothing imagery (Job 29:14; Isa 53:5)', 'a', 'Job 29:15-16 — "I was eyes to the blind, and feet was I to the lame. I was a father to the poor." Isaiah 52:13-53:12 describes a righteous servant who suffers for others. Both texts develop the Hebrew Bible''s theology that innocence and suffering can coexist, a paradox only resolved in NT Christology.');

-- ═══ Job Chapter 30 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Job', 30, 'kids', 1, 'Who was now mocking Job in chapter 30?', 'Young men whose fathers he would have disdained to have set with the dogs of his flock', 'The princes of the city who had once honoured him', 'His three friends who refused to believe his innocence', 'The servants of his household who had once obeyed him', 'a', 'Job 30:1 — "But now they that are younger than I have me in derision, whose fathers I would have disdained to have set with the dogs of my flock."'),
('Job', 30, 'kids', 2, 'What did Job say about his skin?', 'My skin is black upon me, and my bones are burned with heat', 'My skin has become as thin as parchment and falls from my body', 'My skin is covered with sores that will not heal', 'My skin is as cold as the grave and my body waxes cold', 'a', 'Job 30:30 — "My skin is black upon me, and my bones are burned with heat."'),
('Job', 30, 'kids', 3, 'What did Job look for but was unable to find?', 'I looked for good, then evil came; and I waited for light, there came darkness', 'He looked for a friend to sit with him but all had gone away', 'He waited for rain to cool his skin but none fell from heaven', 'He searched for a physician to heal him but none would come near', 'a', 'Job 30:26 — "When I looked for good, then evil came unto me: and when I waited for light, there came darkness."'),
-- Teens
('Job', 30, 'teens', 1, 'How did Job describe the outcasts who now mocked him?', 'They were driven forth from among men, they cried after them as after a thief; to dwell in the cliffs of the valleys, in caves of the earth and in the rocks', 'They were the sons of worthless men who had been banished for stealing', 'They were the lowest of all peoples, driven from every city and tribe', 'They were beggars who lived at the city gates and cursed all who passed by', 'a', 'Job 30:5-6 — "They were driven forth from among men...to dwell in the cliffs of the valleys, in caves of the earth, and in the rocks."'),
('Job', 30, 'teens', 2, 'What did Job say God had done to him with his terrors?', 'Thou liftest me up to the wind; thou causest me to ride upon it, and dissolvest my substance', 'God had thrown me into the fire of his anger and left me to burn', 'He has turned me over to the enemy and left me without a defender', 'God has locked me in a pit with no ladder to climb out', 'a', 'Job 30:22 — "Thou liftest me up to the wind; thou causest me to ride upon it, and dissolvest my substance."'),
('Job', 30, 'teens', 3, 'What did Job say God refused to do when he called and prayed?', 'I cry unto thee, and thou dost not hear me: I stand up, and thou regardest me not', 'God would not answer though Job offered sacrifice and burnt offering', 'God turned his face away when Job stretched out his hands in prayer', 'He did not send an angel to comfort Job though he prayed night and day', 'a', 'Job 30:20 — "I cry unto thee, and thou dost not hear me: I stand up, and thou regardest me not."'),
('Job', 30, 'teens', 4, 'What musical instruments did Job mention that his voice had become like?', 'My harp also is turned to mourning, and my organ into the voice of them that weep', 'My lute is silent and my timbrel is cracked and cannot be played', 'The songs I sang in my prosperity are now the taunts of my enemies', 'My singing has become wailing and my laughter has been turned to weeping', 'a', 'Job 30:31 — "My harp also is turned to mourning, and my organ into the voice of them that weep."'),
('Job', 30, 'teens', 5, 'What compassionate deeds had Job done for the poor that God now seemed to ignore?', 'Did not I weep for him that was in trouble? was not my soul grieved for the poor?', 'I clothed the naked and gave bread to the hungry and God saw it all', 'I freed those in bondage and redeemed those sold into slavery', 'I healed the sick and buried the dead without any reward for myself', 'a', 'Job 30:25 — "Did not I weep for him that was in trouble? was not my soul grieved for the poor?"'),
-- Adults
('Job', 30, 'adults', 1, 'What is the literary structure of Job 30 and how does it function as the contrasting panel to chapter 29?', 'Chapter 29 depicts past honour (young men hiding, elders rising, princes silent, widow''s heart singing) and chapter 30 depicts present humiliation (the lowest social outcasts mocking him, God ignoring his cries, his body dissolving) — a sustained antithetical parallelism', 'Chapter 30 is a continuation of chapter 29 describing the same time period from a different angle', 'The two chapters are structurally unrelated and are joined only because they share the theme of community', 'Chapter 30 moves forward in time to describe Job''s recovery while chapter 29 is the low point', 'a', 'Job 29 vs 30: honour/shame; God''s candle/God''s terrors; respected elders/mocking youth; widow''s singing heart/Job''s mourning harp (30:31); blessing/darkness (30:26). The antithetical structure makes the contrast visceral and rhetorically powerful.'),
('Job', 30, 'adults', 2, 'What does Job''s description of his mockers in Job 30:1-8 reveal about the social dynamics of suffering in the ancient world?', 'Job identifies a reversal of the social hierarchy — men whose fathers he would not have trusted with his dogs now mock him — showing that social suffering strips away the protections of status and exposes the sufferer to exploitation by those he formerly pitied', 'Job is expressing class prejudice by dismissing the poor as inherently contemptible', 'The description is symbolic, representing his friends rather than actual social outcasts', 'Job is documenting specific criminals who robbed him during his affliction', 'a', 'Job 30:1,5-8 — the mockers are social outcasts who "dwell in the cliffs of the valleys, in caves." The social inversion is the point: the greatest humiliation is to be mocked by those who themselves have no social standing. Suffering strips Job of all his former protections.'),
('Job', 30, 'adults', 3, 'How does Job 30:20 — "I cry unto thee, and thou dost not hear me: I stand up, and thou regardest me not" — relate to the Psalms of lament?', 'It uses identical lament rhetoric to Psalms such as Ps 22:2 — "I cry in the daytime, but thou hearest not; and in the night season, and am not silent" — establishing that Job''s complaint belongs to the legitimate genre of Biblical lament, not impiety or rebellion', 'Job 30:20 is a blasphemous statement that contradicts the faith expressed in the Psalms', 'The verse shows Job has abandoned prayer and moved to accusation against God', 'Job 30:20 is unique in the Hebrew Bible and has no parallel in lament literature', 'a', 'Job 30:20 and Ps 22:2 use the same structure: crying to God + God not answering. The lament genre validates complaints of divine silence as an acceptable form of prayer. Job is not being impious — he is following established Hebrew lament conventions.'),
('Job', 30, 'adults', 4, 'What does "thou liftest me up to the wind; thou causest me to ride upon it, and dissolvest my substance" (Job 30:22) reveal about Job''s understanding of his affliction''s source?', 'Job directly attributes his dissolution to God — not to Satan, not to fate, not to human enemies — showing he understands the affliction as theologically purposive (from God) even while he protests its injustice', 'Job is using wind imagery to blame the desert storms for his physical suffering', 'Job is confessing that his own sin has dissolved his former goodness', 'Job attributes his suffering to the wind spirit mentioned in the prologue', 'a', 'Job 30:22 — "Thou liftest me up...thou causest me to ride...dissolvest my substance." Throughout the lament, Job addresses God directly as the agent. This theological directness — accusing God while still crying to him — is the distinctive mark of Job''s faith throughout chapter 30.'),
('Job', 30, 'adults', 5, 'What is the significance of Job weeping for the poor in Job 30:25 in the context of his present abandonment?', 'The rhetorical force is ethical reciprocity — Job wept for others in their trouble, but now that he is in trouble, no reciprocal compassion comes from God or man; the comparison exposes the absence of divine response as morally asymmetric', 'Job is boasting about his past charitable deeds to shame God into responding', 'Job is citing his compassion for the poor as a legal merit point in his case against God', 'Job is comparing his compassion to God''s lack thereof as a way of claiming moral superiority', 'a', 'Job 30:25 — "Did not I weep for him that was in trouble? was not my soul grieved for the poor?" The implication: if Job showed compassion to sufferers, why does not God show compassion to Job? The argument is by analogy from human ethics to divine ethics.'),
('Job', 30, 'adults', 6, 'How does the darkness imagery of Job 30:26 — "When I looked for good, then evil came; and when I waited for light, there came darkness" — contrast with Job 29:3?', 'Job 29:3 — "his candle shined upon my head, and by his light I walked through darkness" — describes God''s former presence as light through darkness; Job 30:26 describes the complete reversal: now there is no candle and expected light yields only darkness, marking total divine withdrawal', 'Both verses use darkness as a symbol of evil men, not of God''s presence or absence', 'Job 30:26 is about physical blindness that afflicted Job during his suffering', 'The contrast is between daytime prosperity in ch.29 and nighttime suffering in ch.30', 'a', 'Job 29:3 — walking through darkness by God''s light = former presence. Job 30:26 — looking for good, finding evil; looking for light, finding darkness = total reversal. The symmetrical contrast shows how completely God''s light has been extinguished in Job''s experience.'),
('Job', 30, 'adults', 7, 'What does the image of the skin being black and bones burning in Job 30:30 contribute to the book''s portrait of suffering?', 'It presents suffering as a total bodily reality — skin blackened by disease (perhaps elephantiasis or severe dermatitis), bones burning with fever — showing that Job''s crisis is not merely spiritual or social but involves catastrophic physical dissolution of his very body', 'The black skin is a poetic expression of shame rather than a physical description', 'Job is describing the effects of the east wind sun-burning his body as he sat in the ash heap', 'The verse describes Job''s mourning practices of covering himself with ash', 'a', 'Job 30:30 — "My skin is black upon me, and my bones are burned with heat." Combined with Job 2:7 — "sore boils from the sole of his foot unto his crown" — the book portrays a comprehensive physical catastrophe that is inseparable from Job''s theological and social suffering.'),
('Job', 30, 'adults', 8, 'What is the theological significance of the final verse of Job 30 — "My harp also is turned to mourning, and my organ into the voice of them that weep"?', 'Music as joy has been converted to music as mourning — the instruments that expressed praise and festivity in Job''s prosperous life now can only express grief; this inversion of worship reflects the inversion of his entire relationship with God and community', 'The verse is a practical complaint that Job''s instruments were damaged in the disaster', 'Job is quoting Psalm 137 about Babylonian captivity as an analogy for his own exile', 'The musical imagery shows Job is preparing a lament psalm to sing before God in his final defence', 'a', 'Job 30:31 — "My harp also is turned to mourning, and my organ into the voice of them that weep." The harp (kinnor) was the instrument of joyful praise (Ps 33:2). Its conversion to mourning marks the totality of Job''s loss — even worship has been transformed into grief.');

-- ═══ Job Chapter 31 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Job', 31, 'kids', 1, 'What covenant did Job make with his eyes?', 'I made a covenant with mine eyes; why then should I think upon a maid?', 'He promised his eyes would never weep again if God restored him', 'He covenanted to look always toward heaven and not upon earthly riches', 'He made a vow never to look with envy at his neighbour''s goods', 'a', 'Job 31:1 — "I made a covenant with mine eyes; why then should I think upon a maid?"'),
('Job', 31, 'kids', 2, 'What did Job say he would let happen to himself if he had treated his servants badly?', 'If I did despise the cause of my manservant or of my maidservant let God punish me', 'He said he would give all his wealth to the poor', 'He said he would sit in the ashes and fast for forty days', 'He said he would never rise from the ground until God answered him', 'a', 'Job 31:13 — "If I did despise the cause of my manservant or of my maidservant, when they contended with me...What then shall I do when God riseth up?"'),
('Job', 31, 'kids', 3, 'What did Job say he wanted God to do — as if signing his name to a document?', 'Oh that one would hear me! behold, my desire is, that the Almighty would answer me, and that mine adversary had written a book', 'He wanted God to send a messenger to tell him what sin he had committed', 'He desired God to write his name in the book of the righteous', 'He asked God to show him the path to wisdom as a written map', 'a', 'Job 31:35 — "Oh that one would hear me! behold, my desire is, that the Almighty would answer me, and that mine adversary had written a book."'),
-- Teens
('Job', 31, 'teens', 1, 'What did Job say about the Almighty''s portion if he had walked in falsehood?', 'For what portion of God is there from above? and what inheritance of the Almighty from on high? Is not destruction to the wicked? and a strange punishment to the workers of iniquity?', 'God would strike him with every plague of Egypt for speaking lies', 'The Almighty would withdraw his hand of blessing and leave Job to his enemies', 'He said God would weigh his falsehood in the balance and find it too heavy to forgive', 'a', 'Job 31:2-3 — "For what portion of God is there from above? and what inheritance of the Almighty from on high? Is not destruction to the wicked? and a strange punishment to the workers of iniquity?"'),
('Job', 31, 'teens', 2, 'What did Job say about providing for the poor and the widow?', 'If I have withheld the poor from their desire, or have caused the eyes of the widow to fail; or have eaten my morsel myself alone, and the fatherless hath not eaten thereof', 'He fed the widow from his own table and clothed the naked from his wardrobe', 'He gave a tenth of all his increase to the poor every year without fail', 'He built a house for widows at the gate of the city and filled it with food', 'a', 'Job 31:16-17 — "If I have withheld the poor from their desire, or have caused the eyes of the widow to fail; Or have eaten my morsel myself alone, and the fatherless hath not eaten thereof."'),
('Job', 31, 'teens', 3, 'What did Job say about trusting in gold?', 'If I have made gold my hope, or have said to the fine gold, Thou art my confidence', 'Gold is a blessing from God and the righteous man stores it wisely for his children', 'He said that gold is dust compared to the wisdom God gives', 'Gold is a gift from heaven and those who have it ought to use it well', 'a', 'Job 31:24 — "If I have made gold my hope, or have said to the fine gold, Thou art my confidence."'),
('Job', 31, 'teens', 4, 'What did Job say about rejoicing when his enemy was destroyed?', 'If I rejoiced at the destruction of him that hated me, or lifted up myself when evil found him', 'He said he wept for his enemies and prayed for those who hated him', 'He kept silence when the wicked fell and did not celebrate', 'He gave alms for the poor when his enemies suffered so that God would see his mercy', 'a', 'Job 31:29 — "If I rejoiced at the destruction of him that hated me, or lifted up myself when evil found him."'),
('Job', 31, 'teens', 5, 'What did Job say he never allowed strangers to do?', 'The stranger did not lodge in the street: but I opened my doors to the traveller', 'He never let a stranger enter the gate of his city without a guide', 'He never allowed strangers to speak falsehood in his presence', 'He did not let strangers go hungry when they came to his house', 'a', 'Job 31:32 — "The stranger did not lodge in the street: but I opened my doors to the traveller."'),
-- Adults
('Job', 31, 'adults', 1, 'What literary genre is Job chapter 31, and how does it function as the climax of Job''s entire defence?', 'It is a negative confession — a series of conditional self-imprecations where Job invokes curse upon himself if he has committed specific sins — functioning as the formal legal close of his case and an implicit challenge to God to answer or acknowledge his innocence', 'It is a psalm of praise that concludes Job''s lament cycle by returning to worship', 'It is a legal inventory of Job''s assets presented to God as evidence of his prosperity', 'It is a catalogue of Mosaic commandments that Job recites to show his knowledge of the law', 'a', 'Job 31 follows the form of ancient Near Eastern negative confessions (e.g., Egyptian Book of the Dead, ch.125). Each "if I have done X" clause invokes a self-curse if the statement is false, constituting a sworn deposition before the divine court that Job has invoked throughout the dialogue.'),
('Job', 31, 'adults', 2, 'What is the theological significance of Job''s covenant with his eyes in Job 31:1 as the opening of his oath?', 'By beginning with the inner life (lust of the eyes, not merely overt sexual sin), Job claims moral integrity at the level of intention and desire, not just external behaviour — a depth of ethical accountability exceeding what the friends demanded or what Mosaic law formally required', 'Job opens with eyes because sight is the most important sense in ancient Israelite religion', 'The eye covenant is a ritual formula used in ancient Near Eastern oath-taking with no specific ethical content', 'Job opens with eyes to show that his suffering began when he saw the disasters happening to him', 'a', 'Job 31:1 — "I made a covenant with mine eyes; why then should I think upon a maid?" The covenant addresses internal desire before external action — a more demanding ethical standard than prohibiting the act alone, anticipating Jesus'' teaching in Matthew 5:28.'),
('Job', 31, 'adults', 3, 'How does Job''s treatment of servants in Job 31:13-15 represent a remarkably advanced social ethics for the ancient world?', 'Job claims he not only refrained from abusing servants but actually listened to their legal cause when they had a complaint against him, grounding this in the theological argument that God made both master and servant in the womb', 'Job is simply asserting that he paid his servants fairly and did not beat them', 'Job is claiming his servants were free Israelites rather than enslaved peoples and therefore deserved legal protection', 'Job is following a legal requirement in the law of Moses about servant treatment', 'a', 'Job 31:13-15 — "If I did despise the cause of my manservant or of my maidservant, when they contended with me...Did not he that made me in the womb make him? and did not one fashion us in the womb?" The theological grounding — common humanity before God — is a social ethics that transcends master-slave hierarchy and anticipates Galatians 3:28.'),
('Job', 31, 'adults', 4, 'What does Job''s inclusion of sins against the poor and widow in Job 31:16-22 as oath subjects reveal about the book''s ethics compared to its retribution theology?', 'It shows that the book''s ethical standard is social justice — care for the vulnerable — not merely ritual or cultic purity; this grounds righteousness in the horizontal (human) dimension alongside the vertical (God), making the friends'' purely theological retribution framework inadequate', 'Job is demonstrating that social charity earns divine favour, supporting a merit-based theology', 'The inclusion of poor and widow topics shows Job was following the Levitical holiness code', 'Job mentions the poor and widow because they were the only witnesses to his charitable acts', 'a', 'Job 31:16-22 covers withholding from the poor, causing the widow''s eye to fail, refusing to clothe the naked. These social justice categories appear alongside lust, lying, adultery — treating justice toward the vulnerable as equally fundamental to integrity as personal sexual purity.'),
('Job', 31, 'adults', 5, 'What is the theological critique embedded in Job''s oath about not trusting in gold (Job 31:24-28)?', 'Job lists trusting in riches (v.24-25) alongside worshipping the sun and moon (v.26-27) as equivalent violations — both substitute a created thing for God, making idolatry of wealth morally equivalent to celestial idolatry', 'Job is simply denying that he was greedy, with no broader theological claim about idolatry', 'Job places gold-worship and celestial worship side by side to show the ignorance of pagan religion', 'Job uses the comparison to show that his wealth was given by God and should therefore be acceptable', 'a', 'Job 31:24-27 — "If I have made gold my hope...or if I beheld the sun when it shined...This also were an iniquity to be punished by the judge: for I should have denied the God that is above." Trusting gold = denying God. The equation makes materialism a form of practical idolatry.'),
('Job', 31, 'adults', 6, 'How does Job''s claim in Job 31:29-30 that he did not rejoice over his enemy''s destruction demonstrate an ethical standard exceeding the legal requirements of the Torah?', 'The Torah permitted proportional retaliation but did not prohibit internal rejoicing at enemies'' misfortune; Job''s claim of not gloating or cursing surpasses legal obligation and enters the domain of commanded love of enemy, anticipating Proverbs 24:17 and Matthew 5:44', 'Job is simply asserting that he had no enemies and therefore could not rejoice at their destruction', 'Job''s claim is culturally standard for ancient Near Eastern wisdom and requires no comparison to Torah', 'The Torah explicitly commanded mourning at enemies'' destruction and Job is citing this law', 'a', 'Job 31:29-30 — "If I rejoiced at the destruction of him that hated me...Neither have I suffered my mouth to sin by wishing a curse to his soul." Prov 24:17 — "Rejoice not when thine enemy falleth." The standard goes beyond legal compliance to inner disposition.'),
('Job', 31, 'adults', 7, 'What does Job''s demand in Job 31:35 — "that mine adversary had written a book" — reveal about his legal strategy and his theology of accountability?', 'Job demands a written indictment from God — a formal charge sheet — so that he can know specifically what he is accused of and answer it publicly; this transforms his suffering from vague divine displeasure into a formal legal confrontation that God is obligated to answer', 'Job is demanding that God produce written evidence of Job''s sins before the court of heaven', 'Job is asking for a written revelation of God''s will that he can study and follow', 'Job desires a book recording all his righteous deeds as evidence of his innocence', 'a', 'Job 31:35 — "Oh that one would hear me! behold, my desire is, that the Almighty would answer me, and that mine adversary had written a book." The demand for a written indictment forces God into the role of prosecuting counsel who must produce charges — or acknowledge Job''s innocence. God responds in chs.38-41.'),
('Job', 31, 'adults', 8, 'How does Job chapter 31 as a whole contribute to the book''s implicit Christology, particularly in light of Hebrews 4:15?', 'Job''s exhaustive inventory of moral integrity — covering lust, lying, adultery, injustice, covetousness, idolatry, hatred, hypocrisy toward God, and mistreating the vulnerable — and his sworn innocence anticipate the NT claim of a high priest "tempted in all points...yet without sin," suggesting Job is a typological adumbration of complete human righteousness', 'Job chapter 31 has no Christological significance since it focuses on human works rather than divine redemption', 'The connection to Hebrews 4:15 is anachronistic since Job predates the NT by centuries', 'Job''s innocence in ch.31 is partial — he admits to some small failures — making him an imperfect type at best', 'a', 'Job 31 covers lust (v.1), lying (v.5), adultery (v.9), mistreating servants (v.13), neglecting poor/widow/orphan (v.16-22), trusting gold/idolatry (v.24-28), hating enemies (v.29-30), hypocrisy (v.33). Hebrews 4:15 — "tempted in all points like as we are, yet without sin." Job''s comprehensive innocence makes him a type of the sinless humanity fulfilled in Christ.');
